const nonce = await client.readContract({ address: TOKEN, abi: ERC20_PERMIT_ABI, functionName: 'nonces', args: [agent] });
const deadline = BigInt(Math.floor(Date.now()/1000) + 1800);

const signature = await wallet.signTypedData({
  domain: { name: 'USD Coin', version: '2', chainId: 1, verifyingContract: TOKEN },
  types: { Permit: [/* ... */] },
  primaryType: 'Permit',
  message: { owner: agent, spender: SPENDER, value: amount, nonce, deadline }
});
const { v, r, s } = parseSignature(signature);

await wallet.writeContract({
  address: TOKEN, abi: ERC20_PERMIT_ABI, functionName: 'permit',
  args: [agent, SPENDER, amount, deadline, v, r, s]
});
